import {getI18n,sptI18n,useSptTranslation} from "@spotter/i18n-sdk";

declare global {
    interface Window {
        __SPOTTER_APP_BOOT_DATA__?: CommonApplicationBootData & Record<string, any>;
        // 国际化实例,这里会在主应用i18n init完成后挂载到window
        __SPOTTER_I18N_DATA__:MainI18n;
    }
}
export interface MainI18n {
    i18n: ReturnType<typeof getI18n>,
    sptI18n:typeof sptI18n,
    useSptTranslation:typeof useSptTranslation,
}
export interface CommonApplicationBootData {
    // 应用编码
    appCode: string,
    // 应用组编码
    appGroupCode: string,
    // 应用模板版本
    version: string,
    // 应用名称
    appName: string,
    // SSO 认证 API 请求头字段,
    ssoTokenHeader: string,
    // SSO 应用认证凭据
    ssoAuthToken: string,
    // iam api 地址
    iamApiUrl: string,
    // Spotter api 网关地址
    appApiUrl: string,
    // 应用环境
    env: string,
    // 应用 CDN 域名
    cdnDomainUrl: string,
    // 部署地区，例如 cn/us
    region: string
}



/**
 * 获取应用的初始化数据
 * @TODO 暂时不支持动态扩展初始化数据的字段
 */
export function getAppBootData<T extends Record<string, any>>(): T & CommonApplicationBootData {
    return window.__SPOTTER_APP_BOOT_DATA__  as  T & CommonApplicationBootData;
}

/**
 * 获取应用挂载的国际化实例
 */
export function getMainI18n(){
    return window.__SPOTTER_I18N_DATA__;
}



